    var merged = {};
    var sources = [
        fluentPlayer, fluentCrm, fchubMemberships, fluentBooking, fluentSecurity
    ];
    for (var i = 0; i < sources.length; i++) {
        var src = sources[i];
        for (var k in src) {
            if (Object.prototype.hasOwnProperty.call(src, k)) {
                merged[k] = src[k];
            }
        }
    }

    return merged;
